def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

# Returns index of target or -1 if not found

import re

def validate_password(password):
    if len(password) < 8:
        return False, 'Password must be at least 8 characters'
    if not re.search(r'[A-Z]', password):
        return False, 'Must contain an uppercase letter'
    if not re.search(r'[a-z]', password):
        return False, 'Must contain a lowercase letter'
    if not re.search(r'\d', password):
        return False, 'Must contain a digit'
    if not re.search(r'[!@#$%^&*(),.?":{}|<>]', password):
        return False, 'Must contain a special character'
    return True, 'Password is valid'

def flatten_dict(d, parent_key='', sep='.'):
    items = []
    for k, v in d.items():
        new_key = f'{parent_key}{sep}{k}' if parent_key else k
        if isinstance(v, dict):
            items.extend(flatten_dict(v, new_key, sep).items())
        else:
            items.append((new_key, v))
    return dict(items)

# Example: flatten_dict({'a': {'b': 1, 'c': {'d': 2}}})
# Returns: {'a.b': 1, 'a.c.d': 2}

def remove_duplicates(lst):
    seen = set()
    result = []
    for item in lst:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result

# Example: remove_duplicates([1, 3, 2, 3, 1, 4, 2])
# Returns: [1, 3, 2, 4]

def roman_to_int(s):
    values = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    result = 0
    for i in range(len(s)):
        if i + 1 < len(s) and values[s[i]] < values[s[i + 1]]:
            result -= values[s[i]]
        else:
            result += values[s[i]]
    return result

# roman_to_int('XIV') -> 14
# roman_to_int('MCMXCIV') -> 1994

class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            return
        current = self.head
        while current.next:
            current = current.next
        current.next = new_node

    def display(self):
        elements = []
        current = self.head
        while current:
            elements.append(current.data)
            current = current.next
        return elements

def are_anagrams(s1, s2):
    s1 = s1.lower().replace(' ', '')
    s2 = s2.lower().replace(' ', '')
    return sorted(s1) == sorted(s2)

# are_anagrams('listen', 'silent') -> True
# are_anagrams('hello', 'world') -> False
